export const DEPLOY_README_TEMPLATE = `# Deploy {{NAME}} ({{TICKER}}) to OPNet Testnet

**Generated:** {{GENERATED_AT}}
**Build hash:** \`{{BUILD_HASH}}\`

---

## Quick deploy

### 1. Compile the contract

\`\`\`bash
cd contract
npm install
npm run build
# → Outputs: contract/build/{{TICKER}}.wasm
\`\`\`

### 2. Get testnet BTC

Fund your deployer wallet (you'll need ~100,000 sat):

\`\`\`bash
# First, find your address:
npx ts-node -e "
const { Mnemonic } = require('@btc-vision/transaction');
const { networks } = require('@btc-vision/bitcoin');
const m = new Mnemonic(process.env.OPNET_MNEMONIC, '', networks.opnetTestnet);
const w = m.derive(0);
console.log('Address:', w.p2tr);
m.zeroize(); w.zeroize();
"
\`\`\`

Then get testnet BTC from a Signet faucet (OPNet uses Bitcoin Signet):
- https://faucet.opnet.org
- https://signet.bc-2.jp/

### 3. Set your mnemonic

\`\`\`bash
export OPNET_MNEMONIC="word1 word2 word3 ... word24"
\`\`\`

⚠️  NEVER commit your mnemonic. Environment variable only.

### 4. Run the deploy script

\`\`\`bash
npm install
npx ts-node deploy.ts
\`\`\`

Expected output:
\`\`\`
Contract address: bcrt1p...
Deploy TX: <txid>
✓ Deployed successfully!
\`\`\`

### 5. After deployment

Copy the contract address and deploy TX, then update the project via the OPFun API:

\`\`\`bash
curl -X POST http://localhost:3001/projects/{{PROJECT_ID}}/confirm-deploy \\
  -H "Content-Type: application/json" \\
  -H "X-Admin-Secret: YOUR_ADMIN_SECRET" \\
  -d '{
    "contractAddress": "bcrt1p...",
    "deployTx": "<txid>",
    "buildHash": "{{BUILD_HASH}}"
  }'
\`\`\`

---

## Security defaults

This contract has **safe defaults enforced**:

| Property | Value | Risk |
|----------|-------|------|
| canMint | false | LOW — fixed supply |
| canPause | false | LOW — always transferable |
| hasAdminKey | false | LOW — no privileged addresses |
| canUpgrade | false | LOW — logic is permanent |

---

## Network

**TESTNET ONLY.** Target: OPNet Testnet (Bitcoin Signet fork)
- RPC: https://testnet.opnet.org
- Must use \`networks.opnetTestnet\` from \`@btc-vision/bitcoin\`
- NEVER use \`networks.testnet\` — that is Bitcoin Testnet4 (incompatible)
`;

export function generateDeployScript(vars: {
  name: string;
  ticker: string;
  buildHash: string;
  generatedAt: string;
}): string {
  return DEPLOY_SCRIPT_TEMPLATE
    .replace(/\{\{NAME\}\}/g, vars.name)
    .replace(/\{\{TICKER\}\}/g, vars.ticker)
    .replace(/\{\{BUILD_HASH\}\}/g, vars.buildHash)
    .replace(/\{\{GENERATED_AT\}\}/g, vars.generatedAt);
}

export function generateDeployPackageJson(vars: { slug: string; name: string; ticker: string }): string {
  return DEPLOY_PACKAGE_JSON
    .replace(/\{\{SLUG\}\}/g, vars.slug)
    .replace(/\{\{NAME\}\}/g, vars.name)
    .replace(/\{\{TICKER\}\}/g, vars.ticker);
}

export function generateDeployReadme(vars: {
  name: string;
  ticker: string;
  slug: string;
  buildHash: string;
  generatedAt: string;
  projectId: string;
}): string {
  return DEPLOY_README_TEMPLATE
    .replace(/\{\{NAME\}\}/g, vars.name)
    .replace(/\{\{TICKER\}\}/g, vars.ticker)
    .replace(/\{\{BUILD_HASH\}\}/g, vars.buildHash)
    .replace(/\{\{GENERATED_AT\}\}/g, vars.generatedAt)
    .replace(/\{\{PROJECT_ID\}\}/g, vars.projectId);
}
